    # Access data from the PlayerState singleton
    var savedHealth = PlayerState.Instance.Health
    var lastPosition = PlayerState.Instance.Last2DPosition

    # Use the saved data
    stats.health = savedHealth
    # ... More code to use the saved position if necessary ...
```

